// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ContractRow) predicate.ContractRow {
	return predicate.ContractRow(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ContractRow) predicate.ContractRow {
	return predicate.ContractRow(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ContractRow) predicate.ContractRow {
	return predicate.ContractRow(sql.NotPredicates(p))
}
